Code.Terraform:
```hcl
# OpenSearch ドメインで詳細なアクセス制御 (FGAC) を有効にする
resource "aws_opensearch_domain" "<example_resource_name>" {
  domain_name = "<example_resource_name>"

  advanced_security_options {
    enabled = true  # 重要: FGAC をオンにします
    master_user_options {
      master_user_arn = "<MASTER_USER_ARN>"  # 重要: IAM プリンシパルを使用して FGAC を有効にするために必要です
    }
  }
}
```
